'<div class="progress-container"',
'     data-ws-url="#WS_URL#"',
'     data-app-user="#APP_USER#"',
'     data-show-all-url="#SHOW_ALL_URL#"',
'     data-max-visible="#MAX_VISIBLE#">',
'',
'   <!-- Big (main) button -->',
'   <button type="button"',
'           class="progress-main shadow"',
'           style="background-color: #BG_COLOR#;"',
'           aria-haspopup="true"',
'           aria-expanded="false"',
'           aria-label="#PROGRESS_LABEL!ATTR#">',
'      <span class="progress-main__content">',
'         <span class="fa #BUTTON_ICON#" style="color: #ICON_COLOR#;" aria-hidden="true"></span>',
'      </span>',
'      <span class="progress-badge" aria-hidden="true"></span>',
'      <span class="sr-only" data-progress-count></span>',
'   </button>',
'',
'   <!-- Rows rendered by APEX from the SQL query, wrapped in a flex column -->',
'   <div class="progress-items"',
'        role="list"',
'        aria-label="#PROGRESS_LABEL!ATTR#">',
'      #APEX$ROWS#',
'   </div>',
'',
'   <!-- Polite live region for status changes (WCAG 4.1.3) -->',
'   <div class="sr-only" aria-live="polite" aria-atomic="false" data-progress-live></div>',
'',
'   <!-- Hidden row prototype: cloned by JS when a new process arrives via WS. -->',
'   <template class="progress-item-tpl">',
'      <div class="progress-item shadow" role="listitem">',
'         <div class="progress-item__body">',
'            <div class="progress-item__name"></div>',
'            <div class="progress-item__status"></div>',
'         </div>',
'      </div>',
'   </template>',
'',
'   <!-- Hidden prototype for the "Show all" overflow row. -->',
'   <template class="progress-showall-tpl">',
'      <div class="progress-item progress-item--show-all shadow" role="listitem">',
'         <a class="progress-item__link" href="" aria-label="Show all running processes">',
'            <div class="progress-item__body">',
'               <div class="progress-item__name">Show all</div>',
'               <div class="progress-item__status">Open overview</div>',
'            </div>',
'         </a>',
'      </div>',
'   </template>',
'</div>',
''))
,p_report_row_template=>wwv_flow_string.join(wwv_flow_t_varchar2(
'<div class="progress-item shadow state-#STATE#"',
